# Add ProvisioningLogs to an existing Entra diagnostic setting
$body = @{
    name = 'entra-all-logs'
    workspaceId = '/subscriptions/<sub>/resourceGroups/<rg>/providers/Microsoft.OperationalInsights/workspaces/<law>'
    logs = @(
        @{ category = 'AuditLogs';        enabled = $true; retentionPolicy = @{days=90;enabled=$true} }
        @{ category = 'SignInLogs';        enabled = $true; retentionPolicy = @{days=90;enabled=$true} }
        @{ category = 'ProvisioningLogs'; enabled = $true; retentionPolicy = @{days=90;enabled=$true} }
    )
} | ConvertTo-Json -Depth 10

$uri = 'https://management.azure.com/providers/microsoft.aadiam/diagnosticSettings/entra-all-logs?api-version=2017-04-01-preview'
Invoke-RestMethod -Uri $uri -Method Put -Body $body -ContentType 'application/json' -Headers @{Authorization="Bearer $token"}

resource "azurerm_monitor_aad_diagnostic_setting" "entra_all" {
  name                       = "entra-all-logs"
  log_analytics_workspace_id = azurerm_log_analytics_workspace.main.id

  enabled_log { category = "AuditLogs"        ; retention_policy { enabled = true; days = 90 } }
  enabled_log { category = "SignInLogs"        ; retention_policy { enabled = true; days = 90 } }
  enabled_log { category = "ProvisioningLogs" ; retention_policy { enabled = true; days = 90 } }
}
